  return crosses;\n}\n\nfunction bridgesWouldCross(islands, bridges, from, to) {\n  const a1 = { x: from.x, y: from.y };\n  const a2 = { x: to.x, y: to.y };\n\n  for (const [k, count] of bridges.entries()) {\n    if (!count) continue;\n    const [x1, y1, x2, y2] = k.split(',').map(Number);\n    const b1 = { x: x1, y: y1 };\n    const b2 = { x: x2, y: y2 };\n\n    // If sharing endpoints, it's not a crossing.\n    const sharesEndpoint =\n      (a1.x === b1.x && a1.y === b1.y) ||\n      (a1.x === b2.x && a1.y === b2.y) ||\n      (a2.x === b1.x && a2.y === b1.y) ||\n      (a2.x === b2.x && a2.y === b2.y);\n    if (sharesEndpoint) continue;\n\n    if (segmentIntersectsStrict(a1, a2, b1, b2)) return true;\n  }\n  return false;\n}\n\nexport function computeCurrentCounts(islands, bridges) {\n  const { byXY } = buildOccupancy(islands);\n  const counts = new Map();\n  for (const isl of islands) counts.set(isl.id, 0);\n\n  for (const [k, n] of bridges.entries()) {\n    if (!n) continue;\n    const [x1, y1, x2, y2] = k.split(',').map(Number);\n    const a = byXY.get(`${x1},${y1}`);\n    const b = byXY.get(`${x2},${y2}`);\n    if (!a || !b) continue;\n    counts.set(a.id, (counts.get(a.id) ?? 0) + n);\n    counts.set(b.id, (counts.get(b.id) ?? 0) + n);\n  }\n\n  return counts;\n}\n\nexport function checkConnectivity(islands, bridges) {\n  if (islands.length === 0) return true;\n  const { byXY } = buildOccupancy(islands);\n\n  const adj = new Map();\n  for (const isl of islands) adj.set(isl.id, new Set());\n\n  for (const [k, n] of bridges.entries()) {\n    if (!n) continue;\n    const [x1, y1, x2, y2] = k.split(',').map(Number);\n    const a = byXY.get(`${x1},${y1}`);\n    const b = byXY.get(`${x2},${y2}`);\n    if (!a || !b) continue;\n    adj.get(a.id).add(b.id);\n    adj.get(b.id).add(a.id);\n  }\n\n  const seen = new Set();\n  const stack = [islands[0].id];\n  while (stack.length) {\n    const cur = stack.pop();\n    if (seen.has(cur)) continue;\n    seen.add(cur);\n    for (const nxt of adj.get(cur) || []) {\n      if (!seen.has(nxt)) stack.push(nxt);\n    }\n  }\n\n  return seen.size === islands.length;\n}\n\nexport function canAddBridge(islands, bridges, from, to, delta) {\n  if (!from || !to || from.id === to.id) return { valid: true, error: null };\n\n  if (!areAdjacent(islands, from, to)) {\n    return { valid: false, error: 'Cannot connect non-adjacent islands' };\n  }\n\n  const k = keyFromCoords(from, to);\n  const current = bridges.get(k) ?? 0;\n  const next = current + delta;\n\n  if (next > 2) {\n    return { valid: false, error: 'Max 2 bridges per pair' };\n  }\n\n  if (next < 0) {\n    // removing is always okay\n    return { valid: true, error: null };\n  }\n\n  const counts = computeCurrentCounts(islands, bridges);\n  const fromCount = (counts.get(from.id) ?? 0) + delta;\n  const toCount = (counts.get(to.id) ?? 0) + delta;\n  if (fromCount > from.value || toCount > to.value) {\n    return { valid: false, error: 'Island would exceed its number' };\n  }\n\n  // Only check crossings if we are adding at least one bridge.\n  if (delta > 0 && bridgesWouldCross(islands, bridges, from, to)) {\n    return { valid: false, error: 'Bridges would cross' };\n  }\n\n  return { valid: true, error: null };\n}\n\nexport function isVictory(islands, bridges) {\n  // No crossings:\n  for (const [kA, nA] of bridges.entries()) {\n    if (!nA) continue;\n    const [ax1, ay1, ax2, ay2] = kA.split(',').map(Number);\n    const a1 = { x: ax1, y: ay1 };\n    const a2 = { x: ax2, y: ay2 };\n\n    for (const [kB, nB] of bridges.entries()) {\n      if (!nB) continue;\n      if (kA === kB) continue;\n      const [bx1, by1, bx2, by2] = kB.split(',').map(Number);\n      const b1 = { x: bx1, y: by1 };\n      const b2 = { x: bx2, y: by2 };\n\n      const sharesEndpoint =\n        (a1.x === b1.x && a1.y === b1.y) ||\n        (a1.x === b2.x && a1.y === b2.y) ||\n        (a2.x === b1.x && a2.y === b1.y) ||\n        (a2.x === b2.x && a2.y === b2.y);\n      if