      "keystrokes": "cat > src/App.jsx <<'EOF'\nimport React, { useEffect, useMemo, useState } from 'react';\nimport { PUZZLES, PUZZLE_OPTIONS } from './data/puzzles';\nimport {\n  areIslandsAdjacent,\n  bridgeKey,\n  canAddBridge,\n  computeCurrentCounts,\n  isVictory\n} from './utils/hashiLogic';\n\nconst GRID = 40;\nconst SVG_W = 800;\nconst SVG_H = 600;\n\nfunction islandPixel(isl) {\n  return { cx: isl.x * GRID, cy: isl.y * GRID };\n}\n\nfunction findIslandById(islands, id) {\n  return islands.find((i) => i.id === id) || null;\n}\n\nfunction sortedIslands(islands) {\n  return [...islands].sort((a, b) => a.id - b.id);\n}\n\nfunction neighborsInDirection(islands, from, dir) {\n  // dir: 'left'|'right'|'up'|'down'\n  const candidates = [];\n  for (const isl of islands) {\n    if (isl.id === from.id) continue;\n    if (dir === 'left' && isl.y === from.y && isl.x < from.x) candidates.push(isl);\n    if (dir === 'right' && isl.y === from.y && isl.x > from.x) candidates.push(isl);\n    if (dir === 'up' && isl.x === from.x && isl.y < from.y) candidates.push(isl);\n    if (dir === 'down' && isl.x === from.x && isl.y > from.y) candidates.push(isl);\n  }\n  if (candidates.length === 0) return null;\n  candidates.sort((a, b) => {\n    if (dir === 'left') return b.x - a.x;\n    if (dir === 'right') return a.x - b.x;\n    if (dir === 'up') return b.y - a.y;\n    return a.y - b.y;\n  });\n  const nearest = candidates[0];\n  // must be adjacent in hashi sense (no islands in between)\n  if (!areIslandsAdjacent(islands, from, nearest)) return null;\n  return nearest;\n}\n\nfunction computeBridgeSegments(islands, bridges) {\n  // returns array of { key, count, from:{x,y}, to:{x,y} } using grid coords\n  const byXY = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));\n  const segs = [];\n  for (const [k, count] of bridges.entries()) {\n    if (!count) continue;\n    const [x1, y1, x2, y2] = k.split(',').map(Number);\n    const a = byXY.get(`${x1},${y1}`);\n    const b = byXY.get(`